INSERT OR IGNORE INTO seed_runs (id, phase_id, phase_name, batch_name, environment, status, actor, source_manifest_uri, started_at, completed_at, rows_extracted, rows_inserted, rows_updated, rows_rejected, notes, created_at, updated_at) VALUES ('seed_run_s05_political_foundation_senators_reps_20260421', 'S05', 'Political and Electoral Foundation', 'national-assembly-senators-and-reps', 'production', 'completed', 'replit-agent', 'docs/reports/phase-s05-political-foundation-source-manifest-2026-04-21.md', unixepoch(), unixepoch(), 319, 318, 0, 1, 'Seeded NASS senators and House of Representatives members from the official National Assembly legislators API. NASS source itself reported 74 senators and 245 representatives as of retrieval; the 35 and 115 additional officeholders required to reach 109 and 360 respectively remain unseed pending publication of additional official source rows. No individuals are fabricated.', unixepoch(), unixepoch());

